18	var (
19		addCmd    string
20		addPri    int
21		addDepStr string
22	)
23	
24	func init() {
25		addCommand.Flags().StringVar(&addCmd, "cmd", "", "Shell command to execute (required)")
26		addCommand.Flags().IntVar(&addPri, "priority", 0, "Task priority (higher = more important)")
27		addCommand.Flags().StringVar(&addDepStr, "depends-on", "", "Comma-separated task IDs")
28		rootCmd.AddCommand(addCommand)
29	}
