31	var addCommand = &cobra.Command{
32		Use:   "add <name>",
33		Short: "Add a task to the queue",
34		Args:  cobra.ExactArgs(1),
35		RunE:  runAdd,
36	}
37	
38	func runAdd(cmd *cobra.Command, args []string) error {
39		s := store.NewMemoryStore()
40		defer s.Close()
41		return runAddWithStore(s, args[0], addCmd, addPri, addDepStr, jsonOutput, os.Stdout)
42	}
43	
44	func runAddWithStore(s store.Store, name, cmdStr string, priority int, depStr string, jsonOut bool, w io.Writer) error {
45		if cmdStr == "" {
46			return fmt.Errorf("tq: cannot add task %q: --cmd is required", name)
47		}
48	
49		var deps []string
50		if depStr != "" {
51			deps = strings.Split(depStr, ",")
52			// Validate dependencies exist
53			tasks, err := s.List(store.Filter{})
54			if err != nil {
55				return fmt.Errorf("tq: cannot add task %q: %w", name, err)
56			}
57			existing := make(map[string]bool, len(tasks))
58			for _, t := range tasks {
59				existing[t.ID] = true
60			}
61			for _, d := range deps {
62				if !existing[d] {
63					return fmt.Errorf("tq: cannot add task %q: dependency %q not found", name, d)
64				}
65			}
66		}
67	
68		state := store.StateReady
69		if len(deps) > 0 {
70			state = store.StatePending
71		}
72		if deps == nil {
73			deps = []string{}
74		}
75	
76		// Pre-generate ID
77		b := make([]byte, 4)
78		if _, err := rand.Read(b); err != nil {
79			return fmt.Errorf("tq: cannot add task %q: %w", name, err)
80		}
81		id := hex.EncodeToString(b)
82	
83		task := store.Task{
84			ID:        id,
85			Name:      name,
86			Cmd:       cmdStr,
87			State:     state,
88			Priority:  priority,
89			DependsOn: deps,
90			CreatedAt: time.Now(),
91		}
92	
93		if err := s.Add(task); err != nil {
94			return fmt.Errorf("tq: cannot add task %q: %w", name, err)
95		}
96	
97		if jsonOut {
98			return json.NewEncoder(w).Encode(struct {
99				ID string `json:"id"`
100			}{ID: id})
101		}
102		fmt.Fprintln(w, id)
103		return nil
104	}
