	RunE:  runList,
}

func runList(cmd *cobra.Command, args []string) error {
	s := store.NewMemoryStore()
	defer s.Close()
	return runListWithStore(s, listState, jsonOutput, os.Stdout)
}

// ListTask is the JSON representation of a task in list output.
type ListTask struct {
	ID        string   `json:"id"`
	Name      string   `json:"name"`
	Cmd       string   `json:"cmd"`
	State     string   `json:"state"`
	Priority  int      `json:"priority"`
	DependsOn []string `json:"depends_on"`
	CreatedAt string   `json:"created_at"`
}

func runListWithStore(s store.Store, stateStr string, jsonOut bool, w io.Writer) error {
	var filter store.Filter
	if stateStr != "" {
		st := store.State(stateStr)
		valid := false
		for _, s := range store.AllStates {
			if s == st {
				valid = true
				break
			}
		}
		if !valid {
			names := make([]string, len(store.AllStates))
			for i, s := range store.AllStates {
				names[i] = string(s)
			}
			return fmt.Errorf("tq: invalid state %q (valid: %s)", stateStr, strings.Join(names, ", "))
		}
		filter.State = &st
	}

	tasks, err := s.List(filter)
	if err != nil {
		return fmt.Errorf("tq: cannot list tasks: %w", err)
	}

	// Sort: priority descending, then CreatedAt ascending
	sort.Slice(tasks, func(i, j int) bool {
		if tasks[i].Priority != tasks[j].Priority {
			return tasks[i].Priority > tasks[j].Priority
		}
		return tasks[i].CreatedAt.Before(tasks[j].CreatedAt)
	})

	if jsonOut {
		out := make([]ListTask, len(tasks))
		for i, t := range tasks {
			deps := t.DependsOn
			if deps == nil {
				deps = []string{}
			}
			out[i] = ListTask{
				ID:        t.ID,
				Name:      t.Name,
				Cmd:       t.Cmd,
				State:     string(t.State),
				Priority:  t.Priority,
				DependsOn: deps,
				CreatedAt: t.CreatedAt.Format(time.RFC3339),
			}
		}
		return json.NewEncoder(w).Encode(out)
	}

	if len(tasks) == 0 {
		return nil
	}

	fmt.Fprintf(w, "%-10s%-10s%4s  %-16s%s\n", "ID", "STATE", "PRI", "NAME", "DEPENDS")
	for _, t := range tasks {
		deps := strings.Join(t.DependsOn, ",")
		fmt.Fprintf(w, "%-10s%-10s%4d  %-16s%s\n", t.ID, t.State, t.Priority, t.Name, deps)
	}
	return nil
}

package cmd

import (
	"encoding/json"
	"fmt"
	"io"
	"os"

	"tq/store"

	"github.com/spf13/cobra"
)

type StatusOutput struct {
	Pending int    `json:"pending"`
	Ready   int    `json:"ready"`
	Running int    `json:"running"`
	Done    int    `json:"done"`
	Failed  int    `json:"failed"`
	Dead    int    `json:"dead"`
	Total   int    `json:"total"`
	Health  string `json:"health"`
}

func init() {
	rootCmd.AddCommand(statusCmd)
}

var statusCmd = &cobra.Command{
	Use:   "status",
	Short: "Show queue status",
	RunE:  runStatus,
}

func runStatus(cmd *cobra.Command, args []string) error {
	s := store.NewMemoryStore()
	defer s.Close()
	return runStatusWithStore(s, jsonOutput, os.Stdout)
}

func runStatusWithStore(s store.Store, jsonOut bool, w io.Writer) error {
	tasks, err := s.List(store.Filter{})
	if err != nil {
		return fmt.Errorf("tq: cannot read queue status: %w", err)
	}

	counts := make(map[store.State]int)
	for _, t := range tasks {
		counts[t.State]++
	}

	total := len(tasks)
	h := health(counts, total)

	out := StatusOutput{
		Pending: counts[store.StatePending],
		Ready:   counts[store.StateReady],
		Running: counts[store.StateRunning],
		Done:    counts[store.StateDone],
		Failed:  counts[store.StateFailed],
		Dead:    counts[store.StateDead],
		Total:   total,
		Health:  h,
	}

	if jsonOut {
		return json.NewEncoder(w).Encode(out)
	}

	for _, state := range store.AllStates {
		fmt.Fprintf(w, "%-10s%d\n", state, counts[state])
	}
	fmt.Fprintf(w, "%-10s%d\n", "total", total)
	fmt.Fprintf(w, "%-10s%s\n", "health", h)

	return nil
}

func health(counts map[store.State]int, total int) string {
	switch {
	case total == 0:
		return "empty"
	case counts[store.StateDead] > 0:
		return "unhealthy"
	case counts[store.StateFailed] > 0:
		return "degraded"
	case counts[store.StateRunning] == 0 && counts[store.StateReady] == 0 && counts[store.StateDone] > 0:
		return "idle"
	default:
		return "healthy"
	}
}

