	}

	// Pre-generate ID
	b := make([]byte, 4)
	if _, err := rand.Read(b); err != nil {
		return fmt.Errorf("tq: cannot add task %q: %w", name, err)
	}
	id := hex.EncodeToString(b)

	task := store.Task{
		ID:        id,
		Name:      name,
		Cmd:       cmdStr,
		State:     state,
		Priority:  priority,
		DependsOn: deps,
		CreatedAt: time.Now(),
	}

	if err := s.Add(task); err != nil {
		return fmt.Errorf("tq: cannot add task %q: %w", name, err)
	}

	if jsonOut {
		return json.NewEncoder(w).Encode(struct {
			ID string `json:"id"`
		}{ID: id})
	}
	fmt.Fprintln(w, id)
	return nil
}
